"""
MKT Original Commentary — Matthew chapters 7–8
Run: python3 scripts/zc-original-matthew-7-8.py

Source data used:
- data/interlinear/matthew.json
- data/translation/draft/mediating/matthew.json
- data/commentary/mkt-original/matthew.json (existing entries ch1-6 carried forward)

Key decisions in this range:
- mē krinete (7:1): prohibition not against all evaluation but against the presumptuous
  condemnatory judgment that ignores one's own moral situation
- kyrie kyrie (7:21-22): double address as established formula vs. genuine relationship
- ouk egnōn (7:23): perfect/aorist of relationship, not mere cognition
- katharisthi (8:3): the passive imperative — Jesus does not ask the leper to become
  clean but declares/effects his cleansing; unique grammatical usage
- pais (8:6): servant with personal intimacy, not the generic slave (doulos)
- seismos (8:24): the word for earthquake applied to a sea-storm — unusual intensity marker
- ti hēmin kai soi (8:29): Semitic non-involvement formula, not a question
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

MATTHEW = {
  "7": {
    "1": '<p><strong>mē krinete</strong> — do not judge (<em>krinō</em>, present imperative: stop the ongoing practice) — the prohibition is not against all moral evaluation (v.6 requires discriminating judgment about dogs and pigs) but against the presumptuous, condemnatory judgment that sets oneself up as a final tribunal over another. <em>Hina mē krithēte</em> — so that you will not be judged — purpose clause: the prohibition has a self-interested logic as well as a moral one. The passive <em>krithēte</em> (be judged) is a divine passive: God is the agent of the judgment returned upon the judge.</p>',
    "2": '<p><strong>hō gar krimati krinete krithēsesthe</strong> — for with what judgment you judge, you will be judged — the sentence is an antanaclasis: the same word-root (<em>krin-</em>) in three forms (noun, verb, passive future) applied to the one doing the judging. <em>Kai en hō metrō metreite metrēthēsetai hymin</em> — and with the measure you measure, it will be measured to you — <em>metreō/metron</em> (to measure/measure): the commercial imagery of weights and scales applied to moral accountability. The passive <em>metrēthēsetai</em> is again divine passive.</p>',
    "3": '<p><strong>to karphos to en tō ophthalmō tou adelphou sou</strong> — the speck (<em>karphos</em>, a tiny splinter, chip of wood or straw) in your brother\'s eye — <em>karphos</em> is the minimum visible fragment. <em>Tēn de en tō sō ophthalmō dokon</em> — the plank (<em>dokos</em>, a load-bearing beam) in your own eye — the absurdist hyperbole inverts perception: one who cannot see because of a beam in their own eye judges the vision of someone with a splinter. The contrast is not merely one of scale but of self-knowledge.</p>',
    "4": '<p><strong>pōs ereis tō adelphō sou</strong> — how can you say to your brother — <em>pōs</em> introduces a rhetorical impossibility: the question is not "will you say this" but "how can you say this." <em>Aphes ekbalō to karphos ek tou ophthalmou sou</em> — let me take the speck out of your eye — <em>aphes</em> aorist imperative of <em>aphiēmi</em>: let me remove it; the volunteer helper asks permission, all the while blind to their own larger obstruction. <em>Kai idou hē dokos en tō ophthalmō sou</em> — and look, the plank is in your own eye.</p>',
    "5": '<p><strong>hypokrita</strong> — hypocrite — the same word used for religious performers in 6:2,5,16; here applied to the self-deceived judge who sees clearly abroad but not at home. <em>Ekbale prōton ek tou ophthalmou sou tēn dokon</em> — first take the plank out of your own eye — <em>prōton</em> (first) is the structural principle: self-examination precedes correction of others. <em>Kai tote diablepseis ekbalein to karphos ek tou ophthalmou tou adelphou sou</em> — and then you will see clearly (<em>diablepō</em>, to see through/clearly) to remove the speck from your brother\'s eye.</p>',
    "6": '<p><strong>mē dōte to hagion tois kysin</strong> — do not give what is holy to dogs — <em>to hagion</em> (the holy thing, the sacred) and <em>tous margaritas</em> (the pearls) are paired as objects of wisdom-teaching. <em>Kysin</em> (dogs) and <em>tois choirois</em> (pigs) were both ritually unclean animals in Jewish law and metaphors for those who treat sacred things with contempt. <em>Mēpote katapatesousin autous en tois posin autōn kai straphentes rhēxōsin hymas</em> — lest they trample them underfoot and turning tear you to pieces — the reversal: instead of receiving the gift, they destroy both it and the giver. The verse requires discrimination in sharing sacred wisdom, balancing 7:1 which prohibits judicial arrogance.</p>',
    "7": '<p><strong>aiteite kai dothēsetai hymin</strong> — ask and it will be given to you — three present imperatives in sequence: <em>aiteite</em> (ask), <em>zēteite</em> (seek), <em>krouete</em> (knock). The present tense marks all three as ongoing, persistent activities, not one-time requests. <em>Dothēsetai</em> (it will be given) — future passive divine. The progression from asking to seeking to knocking may indicate increasing urgency or effort, or it may be a rhetorical triplet expressing the same reality three ways.</p>',
    "8": '<p><strong>pas gar ho aitōn lambanei</strong> — for everyone who asks receives — the three present active participles (<em>ho aitōn/ho zētōn/ho krouōn</em>) are universal: every one who asks... every one who seeks... every one who knocks. <em>Lambanei</em> (receives), <em>heuriskei</em> (finds), and the passive <em>anoigēsetai</em> (it will be opened) match the three actions of v.7. The movement from imperative to indicative (from command to promise) grounds the exhortation in certainty of outcome.</p>',
    "9": '<p><strong>ē tis estin ex hymōn anthrōpos hon aitēsei ho huios autou arton</strong> — or who among you is a person whose son asks for bread — a rhetorical question expecting "no one." <em>Arton... lithon</em> — bread... stone: similar in shape (round flat bread resembling a flat stone of the region). The question is about the father\'s response: would a father deliberately give what harms when asked for what nourishes? The argument moves from human paternal instinct to divine generosity.</p>',
    "10": '<p><strong>ē kai ichthyn aitēsei</strong> — or if he asks for a fish — <em>ichthyn</em> (fish) and <em>ophīn</em> (snake) are paired as the second analogy: both elongated, similar in shape. <em>Mē ophin epidōsei autō</em> — will he not give him a snake? — <em>mē</em> introduces a question expecting "no" (negative answer). The two analogies (bread/stone, fish/snake) establish by everyday human parental behavior the principle that guides the divine argument in v.11.</p>',
    "11": '<p><strong>ei oun hymeis ponēroi ontes</strong> — if then you, being evil — <em>ponēroi ontes</em>: present active participle acknowledging the moral condition of the disciples without softening it; the argument explicitly includes human sinfulness as the baseline from which the a fortiori (<em>poso mallon</em>, how much more) operates. <em>Oidate domata agatha didonai tois teknois hymōn</em> — know how to give good gifts to your children — <em>oidate</em> (perfect-as-present: you already know). <em>Poso mallon ho patēr hymōn ho en tois ouranois dōsei agatha tois aitousin auton</em> — how much more will your heavenly Father give good things to those who ask him.</p>',
    "12": '<p><strong>panta oun hosa ean thelēte hina poiōsin hymin hoi anthrōpoi</strong> — everything therefore that you want people to do to you — <em>oun</em> (therefore) connects the Golden Rule to what preceded: the character of the heavenly Father (v.11) who gives good things is the ground for treating others as you wish to be treated. <em>Houtōs kai hymeis poieite autois</em> — so also do to them. <em>Houtos gar estin ho nomos kai hoi prophētai</em> — for this is the Law and the Prophets — the same phrase as 5:17; the Golden Rule is not a replacement of the Torah but its concentrated summary (cf. Rom 13:9-10, Gal 5:14).</p>',
    "13": '<p><strong>eiselthate dia tēs stenēs pylēs</strong> — enter through the narrow gate (<em>eiselthate</em>, aorist imperative: a decisive act of entering) — <em>stenē</em> (narrow, constricted) and <em>plateia</em> (wide, broad) are contrasted. <em>Hoti plateia hē pylē kai eurychōros hē hodos hē apagousa eis tēn apōleian</em> — for wide is the gate and spacious the road leading to destruction (<em>apōleia</em>, loss/ruin/perdition). <em>Kai polloi eisin hoi eiserchomenoi di autēs</em> — and many are those entering through it — <em>polloi</em> (many) is not comforting here; popularity is not a mark of the correct path.</p>',
    "14": '<p><strong>hoti stenē hē pylē kai tethlimmenē hē hodos</strong> — for narrow is the gate and constricted (<em>thlibō</em>, to press, squeeze) the road — <em>tethlimmenē</em> perfect passive participle: the road has been narrowed, pressed in from both sides; it is not merely small but actively constrained. <em>Hē apagousa eis tēn zōēn</em> — leading to life — <em>zōē</em> (life) is the counterpart to <em>apōleia</em> (destruction) in v.13. <em>Kai oligoi eisin hoi heuriskontes autēn</em> — and few are those who find it — <em>oligoi</em> (few): the road is so narrow it must be actively found (<em>heuriskontes</em>, present participle: those who are in the process of finding).</p>',
    "15": '<p><strong>prosechete apo tōn pseudoprophētōn</strong> — beware of the false prophets (<em>prosechō apo</em> + genitive: to guard oneself from, hold back from) — <em>pseudoprophētai</em> are not simply inaccurate predictors but those who claim prophetic authority while serving false ends. <em>Hoitines erchontai pros hymas en endymasin probatōn</em> — who come to you in sheep\'s clothing (<em>endymasin</em>, outer garments, what one is dressed in) — the garb of the sheep: the appearance of belonging to the flock. <em>Esōthen de eisin lykoi harpages</em> — but inwardly they are rapacious wolves (<em>harpax</em>, seizing, grasping, predatory).</p>',
    "16": '<p><strong>apo tōn karpōn autōn epignōsesthe autous</strong> — by their fruits you will recognize them (<em>epiginōskō</em>, to know thoroughly, recognize fully — the <em>epi-</em> prefix intensifying the knowing) — the criterion is practical and observable: not their words, charisma, or claimed credentials, but their <em>karpoi</em> (fruits, products, outcomes). <em>Mēti syllegousin apo akanthōn staphylas ē apo tribōlōn syka</em> — do people gather grapes from thornbushes or figs from thistles? — a rhetorical question establishing that plant-type determines fruit-type absolutely.</p>',
    "17": '<p><strong>pan dendron agathon karpous kalous poiei</strong> — every good tree makes good fruit — <em>agathos</em> (intrinsically good, good in nature) vs. <em>sapros</em> (rotten, decayed, spoiled: used for rotting wood and bad fish, Matt 13:48). The logic is ontological: what a thing is determines what it produces. <em>To de sapron dendron karpous ponērous poiei</em> — but the rotten tree makes bad/evil fruit — <em>ponērous</em> (bad, harmful, evil): the same word as "the evil one" in 5:37 and "evil people" in 7:11.</p>',
    "18": '<p><strong>ou dynatai dendron agathon karpous ponērous poiein</strong> — a good tree cannot bear bad fruit — <em>ou dynatai</em> (is not able): the logical impossibility is stated as an ontological incapacity, not merely an improbability. <em>Oude dendron sapron karpous kalous poiein</em> — nor can a rotten tree bear good fruit — the symmetrical impossibility stated in both directions. The botanical logic grounds the identification of false prophets in character rather than in claimed criteria.</p>',
    "19": '<p><strong>pan dendron mē poioun karpon kalon ekkoptetai kai eis pyr balletai</strong> — every tree not bearing good fruit is cut down and thrown into fire — <em>ekkoptetai</em> (present passive: is being cut down) and <em>balletai</em> (present passive: is being thrown into fire) — the present tenses may be gnomic (general truth) or proleptic (anticipating the certain future). The language echoes John the Baptist\'s preaching (3:10: "even now the axe is laid at the root of the trees"). The eschatological fire is the endpoint of fruitlessness.</p>',
    "20": '<p><strong>ara ge apo tōn karpōn autōn epignōsesthe autous</strong> — therefore by their fruits you will recognize them — a near-verbatim repetition of v.16b, forming an inclusio that frames the tree/fruit argument of vv.16-19. <em>Ara ge</em> is an emphatic inferential particle: "therefore indeed," drawing the conclusion firmly. The repetition drives the diagnostic criterion home: fruits are the test, not claims of authority, spiritual experience, or formal credentials.</p>',
    "21": '<p><strong>ou pas ho legōn moi kyrie kyrie eiseleusetai eis tēn basileian tōn ouranōn</strong> — not everyone who says to me "Lord, Lord" will enter the kingdom of heaven — <em>ou pas... all</em>: the distributive negation singles out a subclass of "Lord-sayers" who will not enter. <em>Kyrie kyrie</em> — the doubled address is a Semitic intensifier (cf. "Absalom, Absalom," "Martha, Martha") indicating earnestness or familiarity; but familiarity with the formula does not constitute relationship. <em>Ho de poiōn to thelēma tou patros mou tou en ouranois</em> — but the one doing the will of my Father in heaven — the present active participle marks ongoing, habitual doing.</p>',
    "22": '<p><strong>polloi erousin moi en ekeinē tē hēmera</strong> — many will say to me on that day — <em>ekeinē tē hēmera</em> (that day) is the day of final judgment; the plural <em>polloi</em> warns that this is not an edge case. <em>Kyrie kyrie ou tō sō onomati eprophēteusamen kai tō sō onomati daimonia exebalomen kai tō sō onomati dynamous pollas epoiēsamen</em> — Lord, Lord, did we not prophesy in your name, and in your name drive out demons, and in your name perform many miracles? — three extraordinary religious acts all performed <em>en tō sō onomati</em> (in your name): real acts, apparently, but performed without genuine relationship.</p>',
    "23": '<p><strong>kai tote homologēsō autois hoti oudepote egnōn hymas</strong> — and then I will declare to them: I never knew you — <em>homologeō</em> (to confess, declare openly): the declaration is public and definitive. <em>Oudepote egnōn hymas</em> — I never knew you — <em>oudepote</em> (never at any time) + <em>egnōn</em> (aorist of <em>ginōskō</em>): I knew you not, not even once. <em>Ginōskō</em> in Hebrew thought denotes relational, covenantal knowing (cf. Amos 3:2, "you only have I known" = chosen in covenant relationship). The issue is not information but relationship. <em>Apochōreite ap&#8217; emou hoi ergazomenoi tēn anomian</em> — depart from me you workers of lawlessness (<em>anomia</em>, lawlessness, the opposite of the law-fulfilling righteousness Jesus taught in ch5–6).</p>',
    "25": '<p><strong>kai katebē hē brochē kai ēlthon hoi potamoi kai epneusan hoi anemoi</strong> — the rain came down and the rivers came and the winds blew — three agents of destruction in sequence: rain (<em>brochē</em>), flood-streams (<em>potamoi</em>), winds (<em>anemoi</em>). <em>Kai prosepesan tē oikia ekeinē</em> — and beat against that house — <em>prosepiptō</em> (to fall against, rush against). <em>Kai ouk epesen</em> — and it did not fall — aorist negated: a completed test with a completed non-collapse. <em>Tetheliouto gar epi tēn petran</em> — for it had been founded on the rock — pluperfect passive: the foundation pre-existed the storm and its condition determined the outcome.</p>',
    "26": '<p><strong>pas ho akouōn mou tous logous toutous kai mē poiōn autous</strong> — everyone who hears these words of mine and does not do them — the two-part condition: hearing is present (ongoing), not-doing is also present (habitual omission). The contrast with v.24 is grammatically precise: v.24 has <em>akouōn... kai poiōn</em> (hearing and doing); v.26 has <em>akouōn... kai mē poiōn</em> (hearing and not-doing). <em>Homoiōthēsetai andri mōrō</em> — will be like a foolish man (<em>mōros</em>, the same root as <em>morainō</em>, to become foolish, in 5:13). The foolishness is not intellectual deficiency but the moral failure to act on what one has received.</p>',
    "27": '<p><strong>kai katebē hē brochē kai ēlthon hoi potamoi kai epneusan hoi anemoi</strong> — identical storm-formula to v.25 — the same three agents strike the same way. <em>Kai prosekospan tē oikia ekeinē</em> — and struck against that house — <em>proskoptō</em> (to strike against, stumble into) vs. v.25\'s <em>prosepiptō</em>; both convey the force of the assault. <em>Kai epesen kai ēn hē ptōsis autēs megalē</em> — and it fell, and great was its fall — <em>ptōsis</em> (fall, collapse): the noun from <em>piptō</em>. The greatness of the fall measures the greatness of the investment in false foundation; the more one builds on sand, the more catastrophic the collapse.</p>',
    "28": '<p><strong>kai egeneto hote etelesen ho Iēsous tous logous toutous</strong> — and it came to pass when Jesus finished these words — <em>egeneto hote</em> is a Matthean formula (also 11:1; 13:53; 19:1; 26:1) marking the end of the five great discourses of Matthew\'s Gospel. <em>Etelesen</em> aorist of <em>teleō</em>: completed, finished — the same root as <em>teleios</em> (mature, complete) of 5:48. <em>Exeplessonto hoi ochloi epi tē didachē autou</em> — the crowds were astonished (<em>ekplēssō</em>, to strike out of one\'s wits, astonish thoroughly) at his teaching.</p>',
    "29": '<p><strong>ēn gar didaskōn autous hōs exousian echōn</strong> — for he was teaching them as one having authority (<em>exousia</em>, the right and power to act, legitimate authority from one\'s own standing) — <em>hōs exousian echōn</em>: "as" implies manner but also content; the comparison identifies his mode of speaking. <em>Kai ouch hōs hoi grammateis autōn</em> — and not as their scribes — the scribes taught by citing tradition and precedent (<em>the rabbis say..., it has been transmitted that..., the school of Hillel holds..., the school of Shammai holds...</em>); Jesus teaches on his own authority: "but I tell you" (5:22, 28, 32, 34, 39, 44).</p>'
  },
  "8": {
    "1": '<p><strong>katabanti de autō apo tou orous</strong> — when he came down from the mountain — <em>katabanti</em> dative aorist participle of <em>katabainō</em>: the descent from the mount of teaching (ch5–7) is the frame for the sequence of miracles in ch8–9 that demonstrate the same authority in deeds. <em>Ēkolouthēsan autō ochloi polloi</em> — large crowds followed him — <em>akoloutheo</em> (to follow) is Matthew\'s discipleship verb; the crowds follow physically; the question is whether they follow in commitment.</p>',
    "2": '<p><strong>lepros</strong> — a man with leprosy — <em>lepros</em> covers a range of skin conditions, not necessarily what modern medicine identifies as Hansen\'s disease; the significance is the Levitical uncleanness and social exclusion it imposed (Lev 13-14). <em>Prosekynei autō</em> — was bowing before him/worshipping him — <em>proskyneō</em> (to prostrate oneself, do obeisance): the gesture of approach to royalty or deity. <em>Kyrie ean thelēs dynastai me katharisai</em> — Lord, if you are willing, you are able to cleanse me — a careful formulation: the leper affirms Jesus\'s power without presuming his will.</p>',
    "3": '<p><strong>kai ekteinas tēn cheira ēpsato autou</strong> — and stretching out his hand he touched him — <em>ekteinas</em> aorist participle: deliberately extending the hand toward the unclean; <em>hēpsato</em> aorist of <em>haptō</em>, to touch, to grasp. Under Levitical law, contact with a leper conveyed uncleanness to the one who touched; Jesus reverses the direction: his touch cleanses rather than contracting impurity. <em>Thelō katharisthēti</em> — I am willing; be cleansed — <em>thelō</em> (I will/want) answers the leper\'s conditional; <em>katharisthi</em> is an aorist passive imperative — Jesus does not ask the man to become clean but pronounces and effects his cleansing with a single word.</p>',
    "4": '<p><strong>hora mēdeni eipēs</strong> — see that you tell no one — <em>hora</em> (see to it, take heed) + <em>mēdeni eipēs</em> (negative aorist subjunctive: tell no one). This is the first instance of the "messianic secrecy" motif in Matthew: Jesus limits publicity about his identity and works. <em>Alla hypage seauton deixon tō hierei</em> — but go, show yourself to the priest — <em>deixon</em> aorist imperative: the showing is to be the first act, before speaking to anyone. <em>Kai prosenegke to dōron ho prosetaxen Mōysēs</em> — and offer the gift Moses commanded — referring to the cleansing ritual of Lev 14:2-32. <em>Eis martyrion autois</em> — as a testimony to them: the restored leper becomes living proof before the religious authorities.</p>',
    "5": '<p><strong>hekatontarchos</strong> — centurion (commander of 100 soldiers in the Roman army) — a Gentile military officer; the encounter follows immediately after the Jew with leprosy, setting up a Jew/Gentile contrast in responses to Jesus. <em>Parakalōn auton</em> — appealing to him, imploring him (<em>parakaleō</em>, to call alongside, to exhort or beseech): the centurion approaches not as a superior but as a supplicant.</p>',
    "6": '<p><strong>ho pais mou</strong> — my servant/boy (<em>pais</em>) — a word covering both servant and child; it has more personal warmth than the standard slave-word <em>doulos</em>. The centurion\'s concern for his <em>pais</em> establishes the personal stakes. <em>Beblētai en tē oikia paralytikos deinōs basanizomenos</em> — has been thrown (= is lying paralyzed) at home, suffering terribly — <em>beblētai</em> perfect passive: currently in the state of having been cast down; <em>deinōs basanizomenos</em> present passive: continuously being tormented.</p>',
    "7": '<p><strong>kagō elthōn therapeusō auton</strong> — I will come and heal him — the Greek can be read as a direct statement (I will come and heal him) or as a question with implied reluctance (Shall I come and heal him?, raising the social irregularity of a Jewish teacher entering a Gentile household). The ambiguity is unresolved in the text; what matters is that the centurion\'s response in v.8 presupposes the greater point: Jesus\'s authority does not require presence. <em>Elthōn</em> is an aorist participle of <em>erchomai</em>: having come.</p>',
    "8": '<p><strong>kyrie ouk eimi hikanos</strong> — Lord, I am not worthy (<em>hikanos</em>, sufficient, fit, adequate) — the centurion uses the language of social hierarchy: he is not of the rank that would make his household appropriate for Jesus to enter. <em>Alla monon eipe logō</em> — but only say the word — <em>monon</em> (only, merely) + <em>logō</em> (dative: with/by a word alone): a single word from Jesus is sufficient because authority does not require proximity. <em>Kai iathēsetai ho pais mou</em> — and my servant will be healed — <em>iathēsetai</em> future passive: the healing is certain, conditioned only on Jesus\'s word.</p>',
    "10": '<p><strong>ethaumasen</strong> — he marveled (<em>thaumazō</em>, to be astonished) — one of only two occasions in the Gospels where Jesus is said to marvel (the other is Mark 6:6, at unbelief); here he marvels at unusual faith. <em>Para oudeni tosouten pistin en tō Israēl heuron</em> — not in anyone in Israel have I found such faith — <em>tosouten</em> (so great, so large): the faith is not just faith but faith of exceptional magnitude. The observation establishes the inversion: Gentile faith exceeds the faith of the covenant people.</p>',
    "11": '<p><strong>polloi apo anatolōn kai dysmōn hēxousin kai anaklitheēsontai</strong> — many from east and west will come and will recline at table — <em>apo anatolōn kai dysmōn</em> (from risings and settings of the sun, i.e., east and west): a comprehensive geographical merism. <em>Anaklitheēsontai</em> future passive of <em>anaklinō</em> (to recline at table): the eschatological banquet posture. <em>Meta Abraam kai Isaak kai Iakōb en tē basileia tōn ouranōn</em> — with Abraham, Isaac, and Jacob in the kingdom of heaven — the patriarchs serve as the expected guests; the surprise is who else joins them.</p>',
    "12": '<p><strong>hoi de huioi tēs basileias</strong> — the sons of the kingdom — those who by birth and covenant membership expected to inherit the kingdom; the phrase simultaneously acknowledges their special status and subverts the presumption that status guarantees entry. <em>Ekblēthēsontai eis to skotos to exōteron</em> — will be thrown into the outer darkness — <em>ekballō</em> future passive: the same verb used for exorcism (throwing out demons). <em>Skotos to exōteron</em> (the outermost darkness): outside the light of the feast. <em>Ekei estai ho klauthmos kai ho brygmos tōn odontōn</em> — there will be weeping and gnashing of teeth — a Matthean formula (also 13:42,50; 22:13; 24:51; 25:30): the reaction of those excluded from the eschatological celebration.</p>',
    "13": '<p><strong>hōs episteusan</strong> — as you believed — <em>hōs</em> (as) + aorist subjunctive: the healing corresponds exactly and immediately to the faith expressed. <em>Iathē ho pais</em> — the servant was healed — aorist passive: completed action. <em>En tē hōra ekeinē</em> — at that very hour (<em>hōra</em>, hour; <em>ekeinē</em>, that specific one) — the temporal precision underlines that Jesus\'s word effects instantaneous healing at a distance, confirming the centurion\'s thesis in v.8.</p>',
    "14": '<p><strong>tēn pentheran autou beblēmenēn kai pyresousan</strong> — his mother-in-law lying (in bed) and burning with fever — <em>beblēmenēn</em> perfect passive participle: she has been cast down, prostrated by illness; <em>pyresousan</em> present active participle: actively burning with fever (from <em>pyressō</em>, to have a fever, from <em>pyr</em>, fire). The two participles together describe both her posture (lying immobilized) and her condition (fever raging). The brief scene introduces Peter, whose household is now in Capernaum.</p>',
    "15": '<p><strong>ēpsato tēs cheiros autēs kai aphēken autēn ho pyretos</strong> — he touched her hand and the fever left her — <em>hēpsato</em> aorist of <em>haptō</em> (touched): the same touch-verb as in 8:3 with the leper. <em>Aphēken autēn ho pyretos</em> — the fever left her (<em>aphiēmi</em> aorist: to leave, release) — a near-personification: the fever is spoken of as an agent that departs. <em>Kai ēgerthē kai diēkonei autō</em> — and she rose and was serving him — <em>ēgerthē</em> aorist passive (she was raised); <em>diēkonei</em> imperfect active: the ongoing service. The imperfect marks the restoration as complete and immediately productive.</p>',
    "16": '<p><strong>daimonizomonous pollous prosēnenkan autō kai exebalen ta pneumata logō</strong> — many demon-possessed were brought to him and he drove out the spirits with a word — <em>logō</em> (dative: by/with a word alone): the same principle as the centurion\'s faith (v.8); Jesus\'s authority operates through speech. <em>Kai pantas tous kakōs echontas etherapeusen</em> — and he healed all who were ill (<em>kakōs echō</em>, to have badly, to be in a bad condition: a Greek idiom for illness or suffering). The summary verse covers both exorcism and healing, preparing for the formula-citation of v.17.</p>',
    "18": '<p><strong>idōn de ho Iēsous ochlon peri auton ekeleusen apelthein eis to peran</strong> — seeing the crowd around him he commanded to depart to the other side — <em>ekeleusen</em> aorist of <em>keleuō</em> (to command, order), a strong directive. <em>Eis to peran</em> — to the other side (of the Sea of Galilee): a geographical transition that also carries narrative weight in Matthew as entry into Gentile territory.</p>',
    "19": '<p><strong>kai proselthōn heis grammateus eipen autō</strong> — and one scribe approaching said to him — a scribe (<em>grammateus</em>), a professional Torah scholar and copyist, approaches as a potential disciple. <em>Didaskale akolouthēsō soi hopou ean aperchē</em> — Teacher (<em>didaskalos</em>, note: not "Lord" as Peter and the centurion use), I will follow you wherever you go — the promise is unqualified but the address is professional, not personal. Jesus\'s response addresses the unstated assumption behind the offer.</p>',
    "20": '<p><strong>ho huios tou anthrōpou ouk echei pou tēn kephalēn klinē</strong> — the Son of Man has nowhere to lay (<em>klinē</em> aorist active subjunctive of <em>klinō</em>, to recline, lean) his head — <em>ho huios tou anthrōpou</em> is Jesus\'s self-designation drawn from Dan 7:13-14, where the figure receives eternal kingdom; Matthew\'s irony is that this cosmic figure has no fixed residence. <em>Hai alōpekes phōleous echousin kai ta peteina tou ouranou kataskēnōseis</em> — foxes have dens and birds of the sky have nests: even animals have fixed abode; the Son of Man does not. The saying tests whether the scribe\'s unqualified offer holds when the conditions are disclosed.</p>',
    "21": '<p><strong>heteros de tōn mathētōn autou</strong> — another of his disciples — this person is already a disciple (<em>mathētōn</em> genitive), unlike the scribe of v.19. <em>Kyrie epitrepsōn moi prōton apelthein kai thapsai ton patera mou</em> — Lord, permit me first to go and bury my father — <em>epitrepsōn</em> aorist participle of permission: grant me permission. <em>Prōton</em> (first) is the key word; the request implies that family burial duty takes precedence over immediate discipleship response. In Jewish culture, burial of a parent was among the highest filial obligations.</p>',
    "22": '<p><strong>aphes tous nekrous thapsai tous heautōn nekrous</strong> — let the dead bury their own dead — the most radical of Jesus\'s discipleship sayings. Two senses of <em>nekrous</em> are in play: the physically dead (those who can attend to the burial) and the spiritually dead (those who have no relation to the kingdom of life). <em>Sy de akolouthei moi</em> — but you, follow me — <em>sy</em> emphatic: you, in particular; <em>akolouthei</em> present imperative: begin following and continue. The saying does not forbid burial but places the urgency of kingdom-following above even the most pressing legitimate family obligation.</p>',
    "23": '<p><strong>kai embanti autō eis to ploion ēkolouthēsan autō hoi mathētai autou</strong> — and when he got into the boat his disciples followed him — <em>embanti</em> dative aorist participle: the disciples\' following is triggered by and coordinates with Jesus\'s boarding. The boat becomes the context for the test of faith in v.24-27. <em>Akoloutheo</em> here is both narrative and theological: physical following into the boat is the literal form of the discipleship Jesus demanded in v.22.</p>',
    "24": '<p><strong>kai idou seismos megas egeneto en tē thalassē</strong> — and behold, a great shaking arose on the sea — <em>seismos</em> is the standard word for earthquake (<em>seio</em>, to shake); its application to a sea-storm is unusual and intensifying: the shaking is of the order of an earthquake-like upheaval. <em>Hōste to ploion kalyptesthai hypo tōn kymatōn</em> — so that the boat was being covered by the waves — present passive: the covering is ongoing and the situation worsening. <em>Autos de ekatheuden</em> — but he was sleeping — <em>ekatheuden</em> imperfect: he continued sleeping; the contrast between the disciples\' terror and Jesus\'s sleep underlines the nature of the test.</p>',
    "25": '<p><strong>kai proselthontes ēgeiran auton legontes kyrie sōson apollymetha</strong> — and approaching they woke him saying: Lord, save us, we are perishing — <em>sōson</em> aorist imperative of <em>sōzō</em> (to save, rescue): the same verb used for eternal salvation; here it is physical rescue but the semantic range is never absent in Matthew. <em>Apollymetha</em> present: we are in the process of perishing right now. The address <em>kyrie</em> (Lord) marks the disciples as distinct from the scribe of v.19 who used <em>didaskalos</em> (Teacher).</p>',
    "26": '<p><strong>ti deiloi este oligopistoi</strong> — why are you cowardly (<em>deilos</em>, fearful, cowardly — a word of character failure, not merely an emotion), you of little faith (<em>oligopistoi</em>, the compound from 6:30) — Jesus addresses the character of the fear before addressing the storm. <em>Tote egertheis epetimēsen tois anemois kai tē thalassē</em> — then rising he rebuked the winds and the sea — <em>epetimēsen</em> is the word used for rebuking demons (8:16; 17:18): the storm is addressed as a hostile power subject to command. <em>Kai egeneto galēnē megalē</em> — and there was a great calm (<em>galēnē</em>, the specific word for windless, flat-calm sea).</p>',
    "27": '<p><strong>hoi de anthrōpoi ethaumasan legontes potapos estin houtos</strong> — the men marveled saying: what kind of person is this — <em>potapos</em> (what sort of, of what kind) asks a qualitative question about identity: the category of being Jesus occupies. <em>Hoti kai hoi anemoi kai hē thalassa autō hypakouosin</em> — that even the winds and the sea obey him — <em>hypakouō</em> (to obey, to hear under: to listen submissively): the same obedience-verb used for response to commands. The question the disciples ask ("what kind of person is this?") is the Christological question of the whole Gospel.</p>',
    "28": '<p><strong>eis tēn chōran tōn Gadarēnōn</strong> — into the region of the Gadarenes — a Gentile region east of the Sea of Galilee; the textual tradition varies (Gadarenes, Gergesenes, Gerasenes) reflecting uncertainty about precise location, but all versions agree it is on the eastern (Gentile) shore. <em>Dyo daimonizomenoi ek tōn mnēmeiōn</em> — two demon-possessed men from the tombs — corpse-contamination made the tombs doubly unclean: the men live in the place of ritual impurity. <em>Chalepoi lian</em> — extremely violent (<em>chalepos</em>, harsh, dangerous, difficult): no one could pass.</p>',
    "29": '<p><strong>ti hēmin kai soi</strong> — what to us and to you — a Semitic idiom of non-involvement or hostility (cf. John 2:4): "what do we have to do with you?" or "what business is there between us?", not a question seeking information but a declaration of contested relationship. <em>Hyie tou theou</em> — Son of God — the demons\' identification of Jesus is accurate even where the disciples\' understanding is incomplete (cf. 4:3,6, the devil\'s temptations use the same title). <em>Pro kairou basanisai hēmas</em> — to torment us before the time (<em>kairos</em>, the appointed time of eschatological judgment): the demons know of a future judgment and fear its premature arrival.</p>',
    "30": '<p><strong>hē agelē tōn choirōn pollōn boskomenē</strong> — <em>agelē</em> — a large herd of pigs feeding (<em>boskō</em>, to feed by grazing, to tend; present passive participle) — pigs were unclean animals (Lev 11:7-8) and their presence confirms the Gentile context; Jews would not have kept swine. <em>Makran ap autōn</em> — some distance from them: the herd is within sight but separated.</p>',
    "31": '<p><strong>hoi de daimones parekaloun auton legontes</strong> — the demons implored him saying (<em>parakaleō</em>, to beseech, the same word used of the centurion in v.5) — the demons ask rather than resist; their supplication acknowledges Jesus\'s authority to dispose of them as he chooses. <em>Ei ekballeis hēmas aposteile hēmas eis tēn agelēn tōn choirōn</em> — if you drive us out, send us into the herd of pigs — <em>ei ekballeis</em> (if you drive us out): the demons accept the inevitability of expulsion, requesting only the destination.</p>',
    "32": '<p><strong>hypagete</strong> — go (<em>hypago</em>, aorist imperative: go away, depart) — a single word of command. <em>Hoi de exelthontes apēlthon eis tous choirous</em> — and departing they went into the pigs — the transition is immediate (aorist participles); no resistance is recorded. <em>Kai idou hōrmēsen pasa hē agelē kata tou krēmnou eis tēn thalassan</em> — and behold, the whole herd rushed down the cliff into the sea — <em>hōrmēsen</em> aorist of <em>hormaō</em> (to rush, surge forward, like a breaking wave): a single violent surge. <em>Kai apethanon en tois hydasi</em> — and died in the waters.</p>',
    "33": '<p><strong>hoi de boskontes ephygon kai apelthontes eis tēn polin</strong> — the herdsmen fled and going into the city — <em>ephygon</em> aorist of <em>pheugō</em> (to flee): a flight of fear at what they witnessed. <em>Apēngeilan panta kai ta tōn daimonizomenōn</em> — they reported everything, including the things concerning the demon-possessed men — the two narrative threads (the pigs and the men) are both reported; the city learns of both.</p>',
    "34": '<p><strong>kai idou pasa hē polis exēlthen eis hypantēsin tō Iēsou</strong> — and behold the whole city came out to meet Jesus — <em>exēlthen</em> aorist: a single collective movement out of the city toward him. <em>Kai idontes auton parekalesan hopōs metabē apo tōn horiōn autōn</em> — and seeing him they implored (<em>parakaleō</em> again) that he would depart from their region — the same <em>parakaleō</em> used by the centurion (v.5) and the demons (v.31) now used by the townspeople. The community chooses to lose Jesus rather than the economic disruption and social upheaval his presence brings. The irony: the demons beg to stay in the region; the people beg Jesus to leave it.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'matthew')
    merge_comm(existing, MATTHEW)
    save_comm('mkt-original', 'matthew', existing)
    print('Matthew 7-8 mkt-original written.')

if __name__ == '__main__':
    main()
